import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const Dashboard = () => {
  const [examDate, setExamDate] = useState("");
  const [description, setDescription] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleGeneratePlan = async (e) => {
    e.preventDefault();
    if (!examDate || !description) return alert("Please fill in both fields!");

    setLoading(true);
    try {
      // Calling your StudyPulse backend endpoint
      const response = await axios.post('/api/plan/create', { 
        examDate, 
        syllabus: description 
      });

      // After receiving the day-wise schedule, navigate to the Plan Page
      // We pass the schedule data via the 'state' object
      navigate('/plan', { state: { schedule: response.data.tasks } });
      
    } catch (err) {
      console.error("Plan generation failed:", err);
      alert("Failed to generate plan. Check console for details.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center p-8 bg-gray-50 min-h-screen">
      <div className="bg-white p-6 rounded-lg shadow-md w-full max-w-lg">
        <h1 className="text-2xl font-bold mb-6 text-center text-blue-600">Create Study Plan</h1>
        
        <form onSubmit={handleGeneratePlan} className="space-y-4">
          {/* 1. Date Input */}
          <div>
            <label className="block text-sm font-medium text-gray-700">Exam Date</label>
            <input 
              type="date" 
              className="mt-1 w-full border border-gray-300 rounded-md p-2"
              value={examDate}
              onChange={(e) => setExamDate(e.target.value)}
              required
            />
          </div>

          {/* 2. Description/Syllabus Input */}
          <div>
            <label className="block text-sm font-medium text-gray-700">Syllabus Description</label>
            <textarea 
              className="mt-1 w-full border border-gray-300 rounded-md p-2 h-32"
              placeholder="e.g. Differentiation, Integration, Linear Algebra..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              required
            />
          </div>

          {/* 3. Generate Button */}
          <button 
            type="submit"
            disabled={loading}
            className={`w-full py-3 rounded-md text-white font-bold transition-all ${
              loading ? 'bg-gray-400' : 'bg-blue-600 hover:bg-blue-700'
            }`}
          >
            {loading ? "Generating Schedule..." : "Generate Plan"}
          </button>
        </form>
      </div>
    </div>
  );
};

export default Dashboard;
